selector_to_html = {"a[href=\"#equation-23788b6b-473e-4f26-8e00-727cd2d0e38c\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-23788b6b-473e-4f26-8e00-727cd2d0e38c\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-53440525-f4de-4254-a924-2daab2a18523\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-53440525-f4de-4254-a924-2daab2a18523\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right].\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n f\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><p>El factor de escalamiento dependiente del tiempo <span class=\"math notranslate nohighlight\">\\(t^{\\alpha-1}\\)</span> tiene implicaciones f\u00edsicas interesantes:</p>", "a[href=\"#equation-2ca4bb35-6bd0-4e25-8618-954548f48507\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-2ca4bb35-6bd0-4e25-8618-954548f48507\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-c0924d18-9fab-44ba-add9-0878eea75bba\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-c0924d18-9fab-44ba-add9-0878eea75bba\">\n\\[\\begin{equation}\n \\begin{aligned}\n  t^{1-\\alpha} \\dot{x}_1 &amp;= x_2 \\quad \\Rightarrow \\quad \\dot{x}_1 = t^{\\alpha-1} x_2, \\\\\n  t^{1-\\alpha} \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\quad \\Rightarrow \\quad \\dot{x}_2 = t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-e2acb4cd-7fc0-4f7d-a6d1-f23a37c5c6aa\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-e2acb4cd-7fc0-4f7d-a6d1-f23a37c5c6aa\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= \\sigma^{\\alpha-1}~t^{\\alpha-1}~ x_2, \\\\\n  \\dot{x}_2 &amp;= \\sigma^{\\alpha-1}~t^{\\alpha-1}~ \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right],\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-048f65f0-1633-431f-b414-98dc09fdfd80\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-048f65f0-1633-431f-b414-98dc09fdfd80\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2,\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-742dc3e0-2500-4ac1-9e4d-a7dd808ddfd3\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-742dc3e0-2500-4ac1-9e4d-a7dd808ddfd3\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-278477a1-ae34-40f4-9e5d-83232c01285a\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-278477a1-ae34-40f4-9e5d-83232c01285a\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-simple\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo simple<a class=\"headerlink\" href=\"#pendulo-simple\" title=\"Link to this heading\">#</a></h1><p>Para establecer una l\u00ednea de base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema cl\u00e1sico original del p\u00e9ndulo</strong></p>", "a[href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Decaimiento de la oscilaci\u00f3n de un p\u00e9ndulo debido a un chorro de aire<a class=\"headerlink\" href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>Cabe recordar que la ecuaci\u00f3n presentada por <span id=\"id3\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> est\u00e1 dada como sigue</p>", "a[href=\"#generacion-de-datos-experimentales-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Generaci\u00f3n de datos experimentales sint\u00e9ticos<a class=\"headerlink\" href=\"#generacion-de-datos-experimentales-sinteticos\" title=\"Link to this heading\">#</a></h2><p>Ante la ausencia de datos experimentales f\u00edsicos para esta configuraci\u00f3n espec\u00edfica del p\u00e9ndulo, se generaron datos sint\u00e9ticos para probar rigurosamente el algoritmo de estimaci\u00f3n de par\u00e1metros. El conjunto de datos sint\u00e9ticos se produjo simulando el modelo cl\u00e1sico exacto (<span class=\"math notranslate nohighlight\">\\(\\alpha=1\\)</span>) e inyectando un <span class=\"math notranslate nohighlight\">\\(2\\%\\)</span> de ruido gaussiano para simular las imprecisiones de los sensores en el mundo real.</p><p>Esto proporciona un entorno de validaci\u00f3n controlado: el sistema verdadero subyacente opera precisamente en <span class=\"math notranslate nohighlight\">\\(\\alpha=1\\)</span>, lo que permite evaluar si la optimizaci\u00f3n fraccionaria converge correctamente al l\u00edmite cl\u00e1sico.</p>", "a[href=\"#equation-68d6286d-7673-4cc2-b2a7-3b6086f4539a\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-68d6286d-7673-4cc2-b2a7-3b6086f4539a\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2.\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-con-efectos-de-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo con efectos de chorro de aire<a class=\"headerlink\" href=\"#pendulo-con-efectos-de-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>La ecuaci\u00f3n cl\u00e1sica del p\u00e9ndulo con efectos de chorro de aire fue propuesta por <span id=\"id1\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> y est\u00e1 dada como sigue</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
